import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Row, Col, Card, Table, Button, Space, Typography, 
  Tag, Input, ColorPicker, Empty, Divider, Modal, 
  Form, Select, Popconfirm, Flex, App
} from "antd";
import { 
  ClusterOutlined, PlusOutlined, DeleteOutlined, 
  EditOutlined, SaveOutlined, SettingOutlined,
  BorderOutlined, GatewayOutlined, DotChartOutlined
} from "@ant-design/icons";

const { useToken } = theme;
const { Title, Text } = Typography;

// --- Interfaces ---
interface Attribute {
  id: string;
  name: string;
  type: "Select" | "Boolean" | "Text" | "Number";
  values: string[];
}

interface LabelClass {
  key: string;
  id: string;
  name: string;
  color: string;
  type: "rect" | "polygon" | "keypoint" | "all";
  count: number;
  attributes: Attribute[];
}

// --- Mock Data ---
const initialClasses: LabelClass[] = [
  { key: "1", id: "CLS-001", name: "Worker", color: "#FBBF24", type: "all", count: 1250, attributes: [
    { id: "a1", name: "Color", type: "Select", values: ["Red", "Blue", "White", "Black"] },
    { id: "a2", name: "Truncated", type: "Boolean", values: ["True", "False"] },
    { id: "a3", name: "Occluded", type: "Select", values: ["None", "Partial", "Hidden"] },
  ]},
  { key: "2", id: "CLS-002", name: "Crane", color: "#60A5FA", type: "rect", count: 320, attributes: [] },
  { key: "3", id: "CLS-003", name: "Helmet-On", color: "#34D399", type: "rect", count: 5400, attributes: [] },
  { key: "4", id: "CLS-004", name: "Helmet-Off", color: "#F87171", type: "rect", count: 820, attributes: [] },
  { key: "5", id: "CLS-005", name: "Forklift", color: "#A855F7", type: "polygon", count: 2100, attributes: [] },
];

export default function ClassManagement() {
  const { token } = useToken();
  const { t } = useTranslation(["class", "common"]);
  const { message } = App.useApp();

  // --- States ---
  const [classes, setClasses] = useState<LabelClass[]>(initialClasses);
  const [selectedClass, setSelectedClass] = useState<LabelClass | null>(initialClasses[0]);
  
  // Modals
  const [isClassModalVisible, setIsClassModalVisible] = useState(false);
  const [isAttrModalVisible, setIsAttrModalVisible] = useState(false);
  const [editingAttr, setEditingAttr] = useState<Attribute | null>(null);

  const [form] = Form.useForm();
  const [attrForm] = Form.useForm();

  // --- Handlers: Class ---
  const handleAddClass = () => {
    form.validateFields().then(values => {
      const newCls: LabelClass = {
        key: Date.now().toString(),
        id: `CLS-${(classes.length + 1).toString().padStart(3, '0')}`,
        name: values.name,
        color: typeof values.color === 'string' ? values.color : values.color?.toHexString?.() || "#2563EB",
        type: values.type,
        count: 0,
        attributes: []
      };
      setClasses([...classes, newCls]);
      message.success(t("msg.added"));
      setIsClassModalVisible(false);
      form.resetFields();
    });
  };

  const handleDeleteClass = (key: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setClasses(classes.filter(c => c.key !== key));
    if (selectedClass?.key === key) setSelectedClass(null);
    message.warning(t("delete", { ns: "common" }));
  };

  // --- Handlers: Attribute ---
  const handleOpenAttrModal = (attr?: Attribute) => {
    if (attr) {
      setEditingAttr(attr);
      attrForm.setFieldsValue(attr);
    } else {
      setEditingAttr(null);
      attrForm.resetFields();
    }
    setIsAttrModalVisible(true);
  };

  const handleSaveAttribute = () => {
    attrForm.validateFields().then(values => {
      if (!selectedClass) return;

      const newAttr: Attribute = {
        id: editingAttr?.id || Date.now().toString(),
        name: values.name,
        type: values.type,
        values: values.type === "Select" ? values.values : (values.type === "Boolean" ? ["True", "False"] : [])
      };

      const updatedAttributes = editingAttr
        ? selectedClass.attributes.map(a => a.id === editingAttr.id ? newAttr : a)
        : [...selectedClass.attributes, newAttr];

      const updatedClass = { ...selectedClass, attributes: updatedAttributes };
      setClasses(classes.map(c => c.key === selectedClass.key ? updatedClass : c));
      setSelectedClass(updatedClass);
      
      message.success(t("save", { ns: "common" }));
      setIsAttrModalVisible(false);
    });
  };

  const handleDeleteAttribute = (id: string) => {
    if (!selectedClass) return;
    const updatedClass = { ...selectedClass, attributes: selectedClass.attributes.filter(a => a.id !== id) };
    setClasses(classes.map(c => c.key === selectedClass.key ? updatedClass : c));
    setSelectedClass(updatedClass);
    message.warning(t("delete", { ns: "common" }));
  };

  const getToolIcon = (type: string) => {
      const icons = { rect: <BorderOutlined />, polygon: <GatewayOutlined />, keypoint: <DotChartOutlined />, all: <ClusterOutlined /> };
      return icons[type as keyof typeof icons] || <BorderOutlined />;
  };

  // --- Table Columns ---
  const columns = [
    {
      title: t("title"),
      dataIndex: "name",
      key: "name",
      render: (text: string, record: LabelClass) => (
        <Space>
          <div style={{ width: 12, height: 12, borderRadius: 2, background: record.color }} />
          <Text strong>{text}</Text>
        </Space>
      ),
    },
    {
      title: t("toolType"),
      dataIndex: "type",
      key: "type",
      render: (type: string) => (
        <Space>{getToolIcon(type)} <Text type="secondary" style={{ fontSize: 11 }}>{type.toUpperCase()}</Text></Space>
      ),
    },
    {
      title: t("delete", { ns: "common" }),
      key: "action",
      align: "center" as const,
      width: 60,
      render: (_: any, record: LabelClass) => (
        <Popconfirm title={t("delete", { ns: "common" })} onConfirm={(e) => handleDeleteClass(record.key, e as any)}>
          <Button size="small" type="text" danger icon={<DeleteOutlined />} onClick={(e) => e.stopPropagation()} />
        </Popconfirm>
      ),
    },
  ];

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <style>
        {`
          .image-card-hover:hover {
            transform: translateY(-5px) scale(1.02);
            box-shadow: 0 10px 20px rgba(0,0,0,0.15) !important;
          }
        `}
      </style>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("title")}</Title>
          <Text type="secondary" style={{ fontSize: 12 }}>{t("subtitle")}</Text>
        </div>
        <Flex vertical align="flex-end" gap={8}>
          <Breadcrumb 
            items={[
              { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
              { title: t("title") }
            ]} 
          />
          <Button type="primary" size="small" icon={<PlusOutlined />} style={{ borderRadius: 6 }} onClick={() => setIsClassModalVisible(true)}>{t("addBtn")}</Button>
        </Flex>
      </div>

      <Row gutter={16}>
        <Col span={9}>
          <Card variant="borderless" styles={{ body: { padding: 0 } }} style={{ borderRadius: 12, overflow: "hidden", boxShadow: token.boxShadowTertiary, height: "calc(100vh - 180px)" }}>
            <Table 
              dataSource={classes} 
              columns={columns} 
              pagination={false}
              locale={{ emptyText: t("noObjects", { ns: "common" }) }}
              scroll={{ y: "calc(100vh - 280px)" }}
              onRow={(record) => ({
                onClick: () => setSelectedClass(record),
                style: { cursor: "pointer", background: selectedClass?.key === record.key ? token.colorPrimaryBg : "inherit" }
              })}
            />
          </Card>
        </Col>

        <Col span={15}>
          <Card 
            variant="borderless" 
            title={selectedClass ? `${selectedClass.name} ${t("detailTitle")}` : t("detailTitle")} 
            extra={<Button icon={<SaveOutlined />} type="link" onClick={() => message.success(t("confirm", { ns: "common" }))}>{t("save", { ns: "common" })}</Button>}
            style={{ borderRadius: 12, height: "calc(100vh - 180px)", boxShadow: token.boxShadowTertiary }}
            styles={{ body: { height: "calc(100vh - 250px)", overflowY: "auto" } }}
          >
            {selectedClass ? (
              <Flex vertical style={{ width: "100%" }} gap={24}>
                <Row gutter={24}>
                  <Col span={12}>
                    <Text type="secondary">{t("clsCode")}</Text>
                    <Input value={selectedClass.id} disabled style={{ marginTop: 8 }} />
                  </Col>
                  <Col span={12}>
                    <Text type="secondary">{t("clsColor")}</Text>
                    <div style={{ marginTop: 8 }}>
                      <ColorPicker value={selectedClass.color} showText style={{ width: "100%" }} />
                    </div>
                  </Col>
                </Row>

                <Divider style={{ margin: "12px 0" }} />
                
                <div>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 12, alignItems: "center" }}>
                    <Text strong style={{ fontSize: 16 }}>{t("attr")}</Text>
                    <Button size="small" type="dashed" icon={<PlusOutlined />} onClick={() => handleOpenAttrModal()}>{t("addAttr")}</Button>
                  </div>
                  
                  <div style={{ borderRadius: 8, border: `1px solid ${token.colorBorderSecondary}`, background: token.colorBgContainer, overflow: "hidden" }}>
                    {selectedClass.attributes.length === 0 ? (
                      <Empty description={t("msg.noAttr")} style={{ padding: 32 }} />
                    ) : (
                      selectedClass.attributes.map((item, idx) => (
                        <div key={item.id} style={{ 
                          padding: "16px 20px", 
                          display: "flex", 
                          justifyContent: "space-between", 
                          alignItems: "center",
                          borderBottom: idx === selectedClass.attributes.length - 1 ? "none" : `1px solid ${token.colorBorderSecondary}`,
                          transition: "all 0.3s"
                        }}>
                          <div style={{ flex: 1 }}>
                            <Space size={12}>
                              <Tag color={item.type === "Select" ? "blue" : "purple"} style={{ margin: 0 }}>{item.type}</Tag> 
                              <Text strong style={{ fontSize: 14 }}>{item.name}</Text>
                            </Space>
                            <div style={{ marginTop: 4 }}>
                              <Text type="secondary" style={{ fontSize: 12 }}>{item.values.join(", ")}</Text>
                            </div>
                          </div>
                          <Space>
                            <Button type="text" icon={<EditOutlined />} onClick={() => handleOpenAttrModal(item)} />
                            <Popconfirm title={t("delete", { ns: "common" })} onConfirm={() => handleDeleteAttribute(item.id)}>
                              <Button type="text" danger icon={<DeleteOutlined />} />
                            </Popconfirm>
                          </Space>
                        </div>
                      ))
                    )}
                  </div>
                </div>

                <div style={{ background: token.colorFillAlter, padding: "16px", borderRadius: "8px", border: `1px dashed ${token.colorBorder}` }}>
                  <Space>
                    <SettingOutlined />
                    <Text type="secondary">
                       {t('toolType')}: <Text strong style={{ color: token.colorPrimary }}>{selectedClass.type.toUpperCase()}</Text> / {t('attr')}: <Text strong style={{ color: token.colorSuccess }}>{selectedClass.attributes.length}</Text>
                    </Text>
                  </Space>
                </div>
              </Flex>
            ) : (
              <Empty description={t("select", { ns: "common" })} style={{ marginTop: 120 }} />
            )}
          </Card>
        </Col>
      </Row>

      <Modal title={t("addBtn")} open={isClassModalVisible} onOk={handleAddClass} onCancel={() => setIsClassModalVisible(false)} okText={t("add", { ns: "common" })} cancelText={t("cancel", { ns: "common" })} centered>
        <Form form={form} layout="vertical" style={{ marginTop: 24 }}>
          <Form.Item name="name" label={t("title")} rules={[{ required: true }]}><Input placeholder="Vehicle, Person..." /></Form.Item>
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="type" label={t("toolType")} initialValue="rect" rules={[{ required: true }]}>
                <Select>
                  <Select.Option value="rect">Rectangle (BBox)</Select.Option>
                  <Select.Option value="polygon">Polygon (Poly)</Select.Option>
                  <Select.Option value="keypoint">Keypoint</Select.Option>
                  <Select.Option value="all">All Tools</Select.Option>
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}><Form.Item name="color" label={t("clsColor")} initialValue="#2563EB"><ColorPicker showText style={{ width: "100%" }} /></Form.Item></Col>
          </Row>
        </Form>
      </Modal>

      <Modal title={editingAttr ? t("edit", { ns: "common" }) : t("addAttr")} open={isAttrModalVisible} onOk={handleSaveAttribute} onCancel={() => setIsAttrModalVisible(false)} centered destroyOnHidden>
        <Form form={attrForm} layout="vertical" style={{ marginTop: 24 }}>
          <Form.Item name="name" label={t("attr")} rules={[{ required: true }]}><Input placeholder="Color, Model, Type..." /></Form.Item>
          <Form.Item name="type" label={t("toolType")} initialValue="Select" rules={[{ required: true }]}>
            <Select>
              <Select.Option value="Select">Dropdown (Select)</Select.Option>
              <Select.Option value="Boolean">Yes/No (Boolean)</Select.Option>
              <Select.Option value="Text">Text Input</Select.Option>
              <Select.Option value="Number">Number Input</Select.Option>
            </Select>
          </Form.Item>
          <Form.Item noStyle shouldUpdate={(prev, curr) => prev.type !== curr.type}>
            {({ getFieldValue }) => getFieldValue("type") === "Select" && (
              <Form.Item name="values" label="Options (Enter separated)" rules={[{ required: true }]}>
                <Select mode="tags" style={{ width: "100%" }} placeholder="Add tags..." />
              </Form.Item>
            )}
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
}
